import{_ as a,c as t,o,a5 as s,ds as n,dt as i,du as r,dv as l,dw as c,dx as d,dy as h,dz as m,dA as p,dB as u,dC as g,dD as f,dE as b}from"./chunks/framework.BgIqBWih.js";const E=JSON.parse('{"title":"Quick Formula Editing","description":"","frontmatter":{"title":"Quick Formula Editing"},"headers":[],"relativePath":"docs/guide-equation.md","filePath":"docs/guide-equation.md","lastUpdated":1774511930000}'),y={name:"docs/guide-equation.md"};function _(k,e,q,w,x,M){return o(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="quick-formula-editing" tabindex="-1">Quick Formula Editing <a class="header-anchor" href="#quick-formula-editing" aria-label="Permalink to “Quick Formula Editing”">​</a></h1><p>Liii STEM provides a dedicated <strong>Math Mode</strong> that supports formula <strong>editing</strong>, <strong>numbering</strong>, and <strong>referencing</strong>. It also integrates <a href="./guide-lego-tab.html"><strong>LEGO symbols</strong> and <strong>Tab cycling</strong></a> together with shortcuts such as Magic Paste, helping you write formulas more efficiently.</p><h2 id="what-is-math-mode" tabindex="-1">What Is Math Mode <a class="header-anchor" href="#what-is-math-mode" aria-label="Permalink to “What Is Math Mode”">​</a></h2><p>Liii STEM&#39;s <strong>Math Mode</strong> provides a complete environment for mathematical input. All mathematical content should be entered in this mode.</p><p>In text mode, the toolbar is mainly used to insert text structures such as chapters, sections, and semantic blocks. In Math Mode, the toolbar provides more mathematical symbols. The image below shows the toolbar in the two modes under the default theme.</p><p><img src="'+n+'" alt=""></p><h2 id="enter-math-mode" tabindex="-1">Enter Math Mode <a class="header-anchor" href="#enter-math-mode" aria-label="Permalink to “Enter Math Mode”">​</a></h2><h3 id="use-the-mode-toolbar" tabindex="-1">Use the mode toolbar <a class="header-anchor" href="#use-the-mode-toolbar" aria-label="Permalink to “Use the mode toolbar”">​</a></h3><p>In text mode, click the <code>π</code> button on the mode toolbar to choose inline formulas, single-line formulas, or multi-line formulas.</p><p><img src="'+i+'" alt=""></p><blockquote><p>Note: this <code>π</code> button appears only in text mode. If your cursor is already inside a single-line formula, this <code>π</code> button will not appear. In that case, the shortcuts mentioned below also cannot be used to insert a multi-line formula. At present, multi-line formulas in this situation can only be inserted through the corresponding <span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mtext>LaTeX</mtext></mrow><annotation encoding="application/x-tex">\\LaTeX</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.8988em;vertical-align:-0.2155em;"></span><span class="mord text"><span class="mord textrm">L</span><span class="mspace" style="margin-right:-0.36em;"></span><span class="vlist-t"><span class="vlist-r"><span class="vlist" style="height:0.6833em;"><span style="top:-2.905em;"><span class="pstrut" style="height:2.7em;"></span><span class="mord"><span class="mord textrm mtight sizing reset-size6 size3">A</span></span></span></span></span></span><span class="mspace" style="margin-right:-0.15em;"></span><span class="mord text"><span class="mord textrm">T</span><span class="mspace" style="margin-right:-0.1667em;"></span><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.4678em;"><span style="top:-2.7845em;"><span class="pstrut" style="height:3em;"></span><span class="mord"><span class="mord textrm">E</span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.2155em;"><span></span></span></span></span><span class="mspace" style="margin-right:-0.125em;"></span><span class="mord textrm">X</span></span></span></span></span></span> commands, such as <code>\\align</code> and <code>\\eqnarray</code>.</p></blockquote><h3 id="use-keyboard-shortcuts" tabindex="-1">Use keyboard shortcuts <a class="header-anchor" href="#use-keyboard-shortcuts" aria-label="Permalink to “Use keyboard shortcuts”">​</a></h3><ul><li><p>Inline formula: <code>$</code>. <img src="'+r+'" alt=""></p></li><li><p>Single-line formula: <code>Alt</code> + <code>$</code> / <code>Option</code> + <code>$</code>. <img src="'+l+'" alt=""></p></li><li><p>Multi-line formulas:</p></li></ul><p>Multi-line formulas in <code>\\eqnarray</code> format: <code>Alt</code> + <code>&amp;</code> / <code>Option</code> + <code>&amp;</code>. <img src="'+c+'" alt=""></p><p>Multi-line formulas in <code>\\align</code> format: <code>Ctrl</code> + <code>$</code> / <code>Command</code> + <code>$</code>. <img src="'+d+'" alt=""></p><h2 id="common-questions-and-notes" tabindex="-1">Common Questions and Notes <a class="header-anchor" href="#common-questions-and-notes" aria-label="Permalink to “Common Questions and Notes”">​</a></h2><h3 id="how-to-physically-press-these-shortcuts" tabindex="-1">How to physically press these shortcuts <a class="header-anchor" href="#how-to-physically-press-these-shortcuts" aria-label="Permalink to “How to physically press these shortcuts”">​</a></h3><ul><li><p>Inline formula: press <code>Shift</code> + <code>4</code> at the same time.</p></li><li><p>Single-line formula: hold <code>Alt</code> / <code>Option</code>, then press <code>Shift</code> + <code>4</code>.</p></li><li><p>Multi-line formula in <code>\\eqnarray</code> format: hold <code>Alt</code> / <code>Option</code>, then press <code>Shift</code> + <code>4</code>.</p></li><li><p>Multi-line formula in <code>\\align</code> format: hold <code>Ctrl</code> / <code>Command</code>, then press <code>Shift</code> + <code>4</code>.</p></li></ul><h3 id="what-if-i-forget-the-shortcuts" tabindex="-1">What if I forget the shortcuts <a class="header-anchor" href="#what-if-i-forget-the-shortcuts" aria-label="Permalink to “What if I forget the shortcuts”">​</a></h3><p>If you forget a shortcut, go to <code>Insert</code> -&gt; <code>Mathematics</code> -&gt; <code>Inline formula</code>. The shortcut hint is also shown in that menu.</p><h3 id="why-does-a-shortcut-stop-working" tabindex="-1">Why does a shortcut stop working <a class="header-anchor" href="#why-does-a-shortcut-stop-working" aria-label="Permalink to “Why does a shortcut stop working”">​</a></h3><p>Shortcuts work only when you are using an English input method. If your cursor is already inside a single-line formula, these shortcuts also cannot be used to insert formulas.</p><h2 id="final-rendering" tabindex="-1">Final Rendering <a class="header-anchor" href="#final-rendering" aria-label="Permalink to “Final Rendering”">​</a></h2><ul><li><p>Inline formula <img src="'+h+'" alt=""></p></li><li><p>Single-line formula <img src="'+m+'" alt=""></p></li><li><p>Multi-line formulas: <code>eqnarray</code> and <code>align</code> use different alignment styles</p></li></ul><p>Multi-line formulas in <code>eqnarray</code> format <img src="'+p+'" alt=""></p><p>Multi-line formulas in <code>align</code> format <img src="'+u+'" alt=""></p><h2 id="equation-numbering-and-referencing" tabindex="-1">Equation Numbering and Referencing <a class="header-anchor" href="#equation-numbering-and-referencing" aria-label="Permalink to “Equation Numbering and Referencing”">​</a></h2><h3 id="number-equations" tabindex="-1">Number equations <a class="header-anchor" href="#number-equations" aria-label="Permalink to “Number equations”">​</a></h3><p>In Math Mode, click <code>123</code> on the focus toolbar, or use the <code>\\eq-number</code> command to number formulas.</p><p><img src="'+g+'" alt=""></p><blockquote><p>Piecewise functions can be numbered either as a whole formula or line by line. If you directly select the formula and click <code>123</code> on the focus toolbar, the whole multi-line formula will be numbered.</p></blockquote><p><img src="'+f+'" alt=""></p><blockquote><p><code>eqnarray</code> format supports only line-by-line numbering.</p></blockquote><p><img src="'+b+'" alt=""></p><blockquote><p><code>align</code> format supports only line-by-line numbering.</p></blockquote><h3 id="label-and-reference-equations" tabindex="-1">Label and reference equations <a class="header-anchor" href="#label-and-reference-equations" aria-label="Permalink to “Label and reference equations”">​</a></h3><p>You can add labels to numbered equations in Liii STEM so that they can be referenced later in the document. For detailed guidance, please refer to the following tutorial:</p><p><a href="https://liiistem.cn/docs/guide-lines.html" target="_blank" rel="noreferrer">Cross-Reference and Numbering in Liii STEM</a></p>',38)])])}const P=a(y,[["render",_]]);export{E as __pageData,P as default};
